module counter_8bit(clk, reset, enable, Q);
     input clk;
     input reset;
     input enable;
     output [7:0] Q;

     reg [7:0] Q;

       wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
         if (reset)
             Q <= 8'b0;
         else if (enable)
             Q <= Q + 1;
     end
endmodule
